export default function Hero() {
  return (
    <div className="pb-hero">
      <p className="pb-hero-eyebrow">Sistema de Gestão</p>
      <h1 className="pb-hero-title">
        Agenda <span>Inteligente</span>
      </h1>
      <p className="pb-hero-sub">Gerencie seus clientes com precisão e estilo.</p>
    </div>
  );
}
